scwin.onpageload = function () {
  lc_dtCondition.setSelectedIndex(0);
  gr_InIntendInformation.setColumnVisible('selpchItemNm', false);
  gr_InIntendInformation.setColumnVisible('dptWrkPlCd', false);
  gr_InIntendInformation.setColumnVisible('tplZip', true);
  gr_InIntendInformation.setColumnVisible('osideCdNm', true);
  gr_InIntendInformation.setColumnVisible('ioDt', true);
  gr_InIntendInformation.setColumnVisible('selfVehclNo', true);
};

